import os
import boto3
from botocore.exceptions import ClientError
import joblib
import logging

def load_model_from_s3(bucket_name, model_key, local_path):
    s3 = boto3.client('s3')
    try:
        s3.download_file(bucket_name, model_key, local_path)
        logging.info(f"Model downloaded from s3://{bucket_name}/{model_key}")
        return joblib.load(local_path)
    except ClientError as e:
        logging.error(f"Failed to download model: {e}")
        raise

def get_latest_model_version(bucket_name, model_prefix):
    s3 = boto3.client('s3')
    try:
        response = s3.list_objects_v2(Bucket=bucket_name, Prefix=model_prefix)
        if 'Contents' not in response:
            raise Exception("No models found in bucket")
        
        latest = max(response['Contents'], key=lambda x: x['LastModified'])
        return latest['Key']
    except ClientError as e:
        logging.error(f"Failed to list models: {e}")
        raise

def main():
    model_path = os.environ.get('MODEL_PATH')
    if not model_path:
        raise ValueError("MODEL_PATH environment variable not set")
    
    if model_path.startswith('s3://'):
        s3_path = model_path[5:]  # Remove 's3://' prefix
        bucket_name, *key_parts = s3_path.split('/', 1)
        model_key = key_parts[0] if key_parts else ''
        
        if not model_key:
            # If no key specified, get latest version
            model_prefix = 'models/'  # Adjust prefix as needed
            model_key = get_latest_model_version(bucket_name, model_prefix)
        
        local_model_path = '/tmp/model.pkl'
        model = load_model_from_s3(bucket_name, model_key, local_model_path)
    else:
        # Local path
        model = joblib.load(model_path)
    
    # Your inference code here
    logging.info("Model loaded successfully")
    return model

if __name__ == "__main__":
    logging.basicConfig(level=logging.INFO)
    model = main()